changeSet.sql:
INSERT INTO monster_creature_types (monster_id, creature_type_id)
SELECT m.id, ct.id
FROM seed_stg_mct s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN creature_types ct ON ct.code = s.creature_type_code AND ct.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_creature_types j WHERE j.monster_id = m.id AND j.creature_type_id = ct.id
);
DROP TABLE seed_stg_mct;

INSERT INTO monster_speeds (monster_id, movement_type_id, ft, hover)
SELECT m.id, mt.id, s.ft::int, NULLIF(s.hover, '')::boolean
FROM seed_stg_speeds s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN movement_types mt ON mt.code = s.movement_type_code AND mt.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_speeds j WHERE j.monster_id = m.id AND j.movement_type_id = mt.id
);
DROP TABLE seed_stg_speeds;

INSERT INTO monster_senses (monster_id, sense_type_id, ft)
SELECT m.id, st.id, s.ft::int
FROM seed_stg_senses s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN sense_types st ON st.code = s.sense_type_code AND st.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_senses j WHERE j.monster_id = m.id AND j.sense_type_id = st.id
);
DROP TABLE seed_stg_senses;

INSERT INTO monster_languages (monster_id, language_id)
SELECT m.id, l.id
FROM seed_stg_langs s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN languages l ON l.code = s.language_code AND l.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_languages j WHERE j.monster_id = m.id AND j.language_id = l.id
);
DROP TABLE seed_stg_langs;

INSERT INTO monster_saving_throws (monster_id, ability, bonus)
SELECT m.id, s.ability, s.bonus::smallint
FROM seed_stg_saves s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
WHERE NOT EXISTS (
    SELECT 1 FROM monster_saving_throws j WHERE j.monster_id = m.id AND j.ability = s.ability
);
DROP TABLE seed_stg_saves;

INSERT INTO monster_skill_proficiencies (monster_id, proficiency_skill_id, bonus)
SELECT m.id, ps.id, s.bonus::smallint
FROM seed_stg_skills s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN proficiency_skills ps ON ps.name = s.skill_name
WHERE NOT EXISTS (
    SELECT 1 FROM monster_skill_proficiencies j WHERE j.monster_id = m.id AND j.proficiency_skill_id = ps.id
);
DROP TABLE seed_stg_skills;

INSERT INTO monster_damage_resistances (monster_id, damage_type, note)
SELECT m.id, NULLIF(s.damage_type, ''), NULLIF(s.note, '')
FROM seed_stg_dres s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
WHERE NOT EXISTS (
    SELECT 1 FROM monster_damage_resistances j
    WHERE j.monster_id = m.id AND j.damage_type IS NOT DISTINCT FROM NULLIF(s.damage_type, '')
);
DROP TABLE seed_stg_dres;

INSERT INTO monster_damage_immunities (monster_id, damage_type, note)
SELECT m.id, NULLIF(s.damage_type, ''), NULLIF(s.note, '')
FROM seed_stg_dimm s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
WHERE NOT EXISTS (
    SELECT 1 FROM monster_damage_immunities j
    WHERE j.monster_id = m.id AND j.damage_type IS NOT DISTINCT FROM NULLIF(s.damage_type, '')
);
DROP TABLE seed_stg_dimm;

INSERT INTO monster_damage_vulnerabilities (monster_id, damage_type, note)
SELECT m.id, NULLIF(s.damage_type, ''), NULLIF(s.note, '')
FROM seed_stg_dvul s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
WHERE NOT EXISTS (
    SELECT 1 FROM monster_damage_vulnerabilities j
    WHERE j.monster_id = m.id AND j.damage_type IS NOT DISTINCT FROM NULLIF(s.damage_type, '')
);
DROP TABLE seed_stg_dvul;

INSERT INTO monster_condition_immunities (monster_id, condition_id)
SELECT m.id, c.id
FROM seed_stg_cond s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN bestiary_conditions c ON c.code = s.condition_code AND c.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_condition_immunities j WHERE j.monster_id = m.id AND j.condition_id = c.id
);
DROP TABLE seed_stg_cond;

INSERT INTO monster_habitats (monster_id, habitat_id)
SELECT m.id, h.id
FROM seed_stg_hab s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN habitats h ON h.code = s.habitat_code AND h.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_habitats j WHERE j.monster_id = m.id AND j.habitat_id = h.id
);
DROP TABLE seed_stg_hab;

INSERT INTO monster_treasures (monster_id, treasure_tag_id)
SELECT m.id, t.id
FROM seed_stg_treas s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN treasure_tags t ON t.code = s.treasure_tag_code AND t.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_treasures j WHERE j.monster_id = m.id AND j.treasure_tag_id = t.id
);
DROP TABLE seed_stg_treas;

INSERT INTO monster_sources (monster_id, source_id)
SELECT m.id, src.id
FROM seed_stg_msrc s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN sources src ON src.code = s.source_code AND src.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_sources j WHERE j.monster_id = m.id AND j.source_id = src.id
);
DROP TABLE seed_stg_msrc;

INSERT INTO monster_gear (monster_id, item_id, qty)
SELECT m.id, gi.id, COALESCE(NULLIF(s.qty, '')::smallint, 1)
FROM seed_stg_gear s
JOIN monsters m ON m.source_external_id = s.monster_external_id::bigint
JOIN monster_gear_items gi ON gi.code = s.gear_code AND gi.homebrew_id IS NULL
WHERE NOT EXISTS (
    SELECT 1 FROM monster_gear j WHERE j.monster_id = m.id AND j.item_id = gi.id
);
DROP TABLE seed_stg_gear;

ALTER TABLE monster_features ADD COLUMN IF NOT EXISTS seed_feature_key text;
CREATE TABLE seed_stg_features (
    monster_external_id text, section text, sort_order text,
    name_rusloc text, name_engloc text, kind text,
    recharge_min text, recharge_max text,
    description_rusloc text, description_engloc text,
    attack_type text, attack_bonus text,
    reach_ft text, range_ft text, range_long_ft text,
    save_ability text, save_dc text, feature_key text
);

INSERT INTO feature_damages (feature_id, sort_order, average, dice, damage_type, note)
SELECT f.id, s.sort_order::int, NULLIF(s.average, '')::smallint,
       NULLIF(s.dice, ''), NULLIF(s.damage_type, ''), NULLIF(s.note, '')
FROM seed_stg_feature_damages s
JOIN monster_features f ON f.seed_feature_key = s.feature_key
WHERE NOT EXISTS (
    SELECT 1 FROM feature_damages fd WHERE fd.feature_id = f.id AND fd.sort_order = s.sort_order::int
);
DROP TABLE seed_stg_feature_damages;
ALTER TABLE monster_features DROP COLUMN IF EXISTS seed_feature_key;
